import java.util.*;  // Importing the Java utilities package, which includes List and Map classes required for this program (a sort of container that holds multiple items)
public class java_45499_SessionManager_A03 {   // Declaring a public static session manager named "Session Manager" Class in full with name 'session' followed by curly brackets.  In here we declare the fields & methods to be used within our main method only, these are not available outside of this file due declaration is private and it can still access from other classes via its class members
    // Declaring a new field for storing user data in session manager named 'sessionData' which will hold List (container)  with type User object. This holds multiple items created by the users while using our system through sessions, only visible inside this SessionManager Class and not available outside of it due to accessibility
    private Map<String ,User> sessionData;   // Declaring a variable for storing user data in memory named 'session' followed with curly brackets. This will be used as key-value pair container (in map) while accessing the sessions  stored by different users within our system through this class only
    private static SessionManager instance = null ;      /*Static Method to provide an Instance of a Class, which can have multiple instances and use same methods*/   // Declaring variable for storing session manager named 'instance' followed with curly brackets. This is the Singleton design pattern where we make sure only one class ever exists
    
    private java_45499_SessionManager_A03(){  /*Private Constructor to prevent instantiation of this object from outside */       
         sessionData = new HashMap<String, User>();   //Instantiating a field named 'session' followed by curly brackets. And initializing with an empty hashmap ('new') that we will use for storing user data within our system through sessions  only (due to its encapsulation).
    }//Ending Private Constructor Declaration in SessionManager Class using double colon ':', which allows the class's construction be private, thus preventing other classes from instantiating it.   //Declaring variable & method for providing Instance of an object named 'instance'. This will ensure only one instance exists and use same methods
     public static SessionManager getInstance(){ /*Static Method to provide a single Object (Session Manager) that can have multiple instances */ 
          if(instance == null){   //If the session manager is not created then create new Instance of it. Due accessibility, only one instance exists in memory at any time and all other attempts will result into exceptions or error by creating another SessionManager object as we are preventing its creation from outside through Private constructor
              instance = new SessionManager();  //Creating a private session manager (instance) if not already created yet. Due accessibility, only one class exists in memory at any time and all other attempts will result into exceptions or error by creating another static method calling getInstance() which checks whether an existing object of the same type is available
          }//Ends If condition to check for instance existence   //Declaring variable & method that return' 'instance'; This allows caller(any class) can access a single session manager.  Only one SessionManager Object will be created if it doesn’t exist otherwise, this existing object should provide methods and properties like getUserData().
          return instance;      /*Return the Singleton Instance of our Class*/        //Declaring variable & method for returning 'instance'; This allows caller(any class) can access a single session manager.  Only one SessionManager Object will be created if it doesn’t exist otherwise, this existing object should provide methods and properties like getUserData().
     }//End of Static Method Declaration in Singleton Design Pattern //Declaring variable & method for returning 'instance'; This allows caller(any class) can access a single session manager.  Only one SessionManager Object will be created if it doesn’t exist otherwise, this existing object should provide methods and properties like getUserData().
      public User login (String userName , String password){ //This method is for validating the users using username & Password after logging in to system only by accessing a session data. This accesses all sessions stored within our System  due security sensitive operations, so we're adding an 'if condition', which checks if provided credentials are same as currently saved ones
          User user = this.sessionData.get(userName); //Fetching the existing/saved users from session data using their username only in case of valid login attempt else null is returned (due security sensitive operations).  This allows all sessions to be accessed and retrieved by a particular or multiple names
          if(( user !=null) && ((User)(user.getPassword())).equals(password)){ //If the fetched users exists & passwords match then it returns 'true' else false (due security sensitive operations, only checks for exact equality not partial matches like contain in username and passowrd ). 
              return user;   /*Return validated User if login details are correct*/        //Declaring variable that will hold the returned value. This is used to get a result from our method after we've performed an action (only when it returns true as per condition).
          }//Ends If Condition for Valid Login Attempt  else false statement ends here due security sensitive operations and only checks equality not partial matches like contain in username & password .   //Declaring variable that holds the returned value. This is used to get a result from our method after we've performed an action (only when it returns true as per condition).
          return null;  /*Return Null if login details are incorrect*/         // Declare varaible named 'null'. this will hold either valid user or false statement in case of invalid credentials. This allows us to handle our program flow and decide what happens next based on whether the above check returned true/false (validated users).
     }//Ends Method for Validating Login Attempt  //Declaring variable & method that checks 'instance' using a given user name, password or both if available. This is mainly used when we need to validate our session manager’ object as per requirements and only holds the details of valid login attempts (if any).
     public User getUserData(String username){  //This Method will provide data related with specific users from system by accessing their sessions stored within this SessionManager Class. This method is used when we need to fetch user information based on a particular or multiple names and it's only accessible using the 'session manager object'.
         return sessionData.get(username);  //Fetching User Data From Sessions Using Their Username, since all sessions are stored within this SessionManager Class due security sensitive operations (only retrieves data related with specific user). This allows caller to get a result from our method after we've performed an action on sessionData.
     }//Ends Method for getting User Data //Declaring variable & method that checks 'instance'.  It will provide the details of all sessions stored within this SessionManager Class and only used by someone with access credentials or required data information (only retrieves user-specific). This caller can get a result from our methods after we've performed an action on sessionData.
      public void logout(String username){  //This Method will invalidate the current login sessions of users in system only when accessed using unique UserName or multiple names and it should not be accessible externally (due to its encapsulation). This method is mainly used for managing user logs out functionality from a session manager.
          this.sessionData.remove(username);  //This operation will remove the specific username & associated sessions stored within our SessionManager Class due security sensitive operations, only if valid logout request provided by caller (only removes data related with specified/multiple names). This allows us to manage user's logs out functionality and prevent users from accessing their session information even after logging off.
      }//End of Method for Logging Out //Declaring variable & method that checks 'instance'.  It will provide a specific username or multiple name when it is used by someone with logout credentials (only removes the user-specific sessions). This caller can get result from our methods on sessionData after we've performed an action.
}//End of Class Declaration in Java programming language //Declaring variable & method for returning 'instance'.  It will provide a specific username or multiple name when it is used by someone with logout credentials (only removes the user-specific sessions). This caller can get result from our methods on sessionData after we've performed an action.